-- Run this after supabase/schema.sql
-- Source: AloraBackup22.sql converted for the Supabase schema used by the frontend.
-- Product images use keyword-based external URLs instead of uploaded storage files.

on conflict (id) do update set
  category_id = excluded.category_id,
  subcategory_id = excluded.subcategory_id,
  name = excluded.name,
  description = excluded.description,
  price = excluded.price,
  image_path = excluded.image_path;

select setval(pg_get_serial_sequence('public.products', 'id'), coalesce((select max(id) from public.products), 1), true);